// AGENT: Analytics v1.0.0 — PLACEHOLDER
// In Phase 6, this will:
//  1. INSERT execution record into execution_logs table
//  2. INSERT per-agent timing + token usage into agent_metrics
//  3. UPDATE user aggregate stats
//  4. Compute cost estimate based on model + token usage
//  5. This agent is FIRE-AND-FORGET — never blocks the pipeline

const input = $input.first().json;
const ctx   = input.execution_context;
if (!ctx) {
  console.warn('[analytics] Missing execution_context — skipping');
  return [{ json: { status: 'skipped', reason: 'missing context' } }];
}

const started_at = Date.now();
console.log(`[analytics] START | execution_id=${ctx.execution_id}`);

// PLACEHOLDER: Log analytics summary to console
const analytics_record = {
  execution_id:      ctx.execution_id,
  user_id:           ctx.user_id,
  pipeline_version:  ctx.pipeline_version,
  started_at:        ctx.started_at,
  ended_at:          new Date().toISOString(),
  status:            ctx.pipeline_status || 'completed',
  agents_completed:  ctx.agents_completed?.length || 0,
  agents_failed:     ctx.agents_failed?.length    || 0,
  total_tokens_used: ctx.meta?.total_tokens_used  || 0,
  total_cost_usd:    ctx.meta?.total_cost_usd     || 0,
  total_duration_ms: ctx.meta?.total_duration_ms  || 0,
  jobs_found:        ctx.results?.jobs_merged?.length        || 0,
  jobs_filtered:     ctx.results?.jobs_deduplicated?.length  || 0,
  applications_ready:ctx.results?.application_packets?.length|| 0,
  persisted:         false,
  note:              'PLACEHOLDER — Will persist to execution_logs in Phase 6'
};

console.log('[analytics] Summary:', JSON.stringify(analytics_record, null, 2));

const duration_ms = Date.now() - started_at;
console.log(`[analytics] COMPLETE (placeholder) | duration=${duration_ms}ms`);

return [{
  json: {
    execution_context: ctx,
    analytics_record,
    status: 'placeholder',
    agent_meta: { agent_id: 'agent-analytics', agent_version: '1.0.0', execution_id: ctx.execution_id, model_used: null, tokens_total: 0, duration_ms, status: 'placeholder', error: null }
  }
}];
